DECLARE @BatchSize INT = 5000;
DECLARE @RowsAffected INT = 1;

-- Temp table to hold IDs for deletion
CREATE TABLE #ToDelete (ID INT PRIMARY KEY);

WHILE (@RowsAffected > 0)
BEGIN
    -- Clear temp table from previous iteration
    TRUNCATE TABLE #ToDelete;

    -- Stage IDs first (short-lived shared scan, no delete locks yet)
    INSERT INTO #ToDelete (ID)
    SELECT TOP (@BatchSize) ID
    FROM [change_log].[transactions]
    WHERE DateCreated < DATEADD(HOUR, -72, GETUTCDATE());

    SET @RowsAffected = @@ROWCOUNT;

    IF @RowsAffected > 0
    BEGIN
        -- Delete using PK lookup — narrow, targeted row locks
        DELETE t
        FROM [change_log].[transactions] t
        INNER JOIN #ToDelete d ON d.ID = t.ID;

        -- Optional: slight pause to reduce pressure
        WAITFOR DELAY '00:00:01';
    END
END

DROP TABLE #ToDelete;








